import Sidebar from "./Sidebar";
import Navbar from "./Navbar";

function Layout({children}: any){

return(

<div style={{display:"flex"}}>

<Sidebar/>

<div style={{flex:1}}>

<Navbar/>

<div style={{padding:"20px"}}>

{children}

</div>

</div>

</div>

)

}

export default Layout;
